    def parse_strVal(self, local_follow):
        val, t_type, line, col = self.get_token_info()
        node = {"type": "strVal", "line": line}
        if val == "echo":
            self.pos += 1
            node["kind"] = "echo"
            node["name"] = self.match("ID")
