    def parse_locDecOp(self, local_follow):
        val, t_type, line, col = self.get_token_info()
        node = {"type": "locDecOp", "line": line}
        if val == "=":
            self.pos += 1
            node["value"] = self.parse_exprDec({","} | local_follow)
